import{_ as e,o,c as i,ag as n}from"./chunks/framework.eQLvDOR_.js";const m=JSON.parse(`{"title":"context-optimization","description":"","frontmatter":{"title":"context-optimization","concept":"Context Optimization","concept_id":"context-optimization","aliases":["Usage-Limit-Avoidance","Token-Efficiency"],"sources":["02_Library/AI_Prompt_Engineering/[AI_Prompt_Engineering] I stopped hitting Claude's usage limits - 10 things I changed.md"],"related_concepts":["[[claude-code-mastery]]"],"created_at":"2026-04-07","last_compiled":"2026-04-07"},"headers":[],"relativePath":"wiki/concepts/context-optimization.md","filePath":"wiki/concepts/context-optimization.md","lastUpdated":null}`),a={name:"wiki/concepts/context-optimization.md"};function r(l,t,s,c,g,d){return o(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="context-optimization-上下文优化" tabindex="-1">Context Optimization (上下文优化) <a class="header-anchor" href="#context-optimization-上下文优化" aria-label="Permalink to &quot;Context Optimization (上下文优化)&quot;">​</a></h1><h2 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h2><p>解决 Claude 使用额度限制 (Usage Limits) 的根本方法：减少单次 Prompt 的冗余 Token，最大化利用 Prompt Cache。</p><h2 id="_1-kv-缓存机制-kv-cache-mechanics" tabindex="-1">1. KV 缓存机制 (KV Cache Mechanics) <a class="header-anchor" href="#_1-kv-缓存机制-kv-cache-mechanics" aria-label="Permalink to &quot;1. KV 缓存机制 (KV Cache Mechanics)&quot;">​</a></h2><p>现代 Transformer 模型（如 Claude 3.5/Opus 4.5）依赖 KV Cache（Key-Value Cache）来复用历史计算结果。</p><ul><li><strong>前缀匹配原则</strong>：缓存命中必须从 Prompt 的第一个字符开始完全一致。一旦前缀改变（如修改了 System Prompt 的首行），后续所有缓存全部失效。</li><li><strong>命中收益</strong>：缓存命中的 Token 价格仅为全价的 <strong>1/10</strong>。</li><li><strong>时效性 (TTL)</strong>：Anthropic 的缓存默认有效期为 <strong>1 小时</strong>（对 Pro/Max 用户），或 <strong>5 分钟</strong>（标准 API 用户）。</li><li><strong>Causal Mask</strong>：因果遮罩保证了 Token 序列只能单向引用，因此追加末尾内容不会破坏前面的缓存。</li></ul><h2 id="_2-claude-code-缓存架构-block-1-4" tabindex="-1">2. Claude Code 缓存架构 (Block 1-4) <a class="header-anchor" href="#_2-claude-code-缓存架构-block-1-4" aria-label="Permalink to &quot;2. Claude Code 缓存架构 (Block 1-4)&quot;">​</a></h2><p>Claude Code CLI 通过精密的四层结构来保护缓存：</p><ol><li><strong>Block 1 &amp; 2</strong>：计费归因与 CLI 前缀（不缓存）。</li><li><strong>Block 3 (Global)</strong>：静态指令与行为规则（全球用户共享/长期缓存）。</li><li><strong>Block 4 (Org/Project)</strong>：动态配置（如 <code>CLAUDE.md</code>，通过 <code>cache_control</code> 显式标记）。</li><li><strong>Messages</strong>：对话历史。</li></ol><h2 id="_3-实践指南" tabindex="-1">3. 实践指南 <a class="header-anchor" href="#_3-实践指南" aria-label="Permalink to &quot;3. 实践指南&quot;">​</a></h2><ul><li><strong>保护缓存前缀</strong>：避免在工作进行中修改 <code>CLAUDE.md</code> 或增减 MCP 工具。</li><li><strong>保持 Session 活跃</strong>：在 1 小时内发送一次简短 Prompt（如 &quot;ok&quot;）可实现 <strong>Cache Keep-Alive</strong>，避免大容量 Context 的二次冷启动扣费。</li><li><strong>长上下文预热 (Cache Warmup)</strong>：在进行长达数小时的编码会话前，先发送一个包含全量文档的 <code>warmup</code> 指令，建立基础缓存。</li><li><strong>避免频繁切换模型</strong>：Opus 与 Sonnet 的 KV 张量互不通用，切换模型会导致上下文重算。</li><li><strong>利用 /btw 提问</strong>：子窗口提问不改变主 Session 历史。</li><li><strong>子智能体 (Sub-agents) 开销</strong>：注意每个 Sub-agent 有独立的缓存链，启动 Sub-agent 等于一次“迷你冷启动”。</li><li><strong>上下文分页 (Context Paging)</strong>：效仿操作系统，将对话中非当下的背景事实 Page-out 到内存数据库，仅维持核心逻辑和当前任务锚点在活跃窗口。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/AI_Prompt_Engineering/AI_Prompt_Engineering - 搞懂缓存机制，从Gemma4到Claude Code省80%Token.html">[AI_Prompt_Engineering] 搞懂缓存机制，从Gemma4到Claude Code省80%Token</a></li><li><a href="/s/webclips/library/AI_IDE_And_CLI/AI_IDE_And_CLI - How I run 10K MRR on 20 budget.html">[AI_IDE_And_CLI] How I run 10K MRR on 20 budget</a></li><li><a href="/s/webclips/library/AI_Prompt_Engineering/AI_Prompt_Engineering - I stopped hitting Claude&#39;s usage limits - 10 things I changed.html">[AI_Prompt_Engineering] I stopped hitting Claude&#39;s usage limits - 10 things I changed</a></li><li><a href="/s/webclips/library/AI_Prompt_Engineering/AI_Prompt_Engineering - How to set up Claude Cowork (the April 2026 update)_.html">[AI_Prompt_Engineering] How to set up Claude Cowork (the April 2026 update)_.md</a></li><li><a href="/s/webclips/library/AI_Prompt_Engineering/AI_Prompt_Engineering - Prompting is the worst way to use Claude. Do this instead_.html">[AI_Prompt_Engineering] Prompting is the worst way to use Claude. Do this instead_.md</a></li></ul>',14)])])}const _=e(a,[["render",r]]);export{m as __pageData,_ as default};
